function getVisibleDropdownItems($dropdown){return $dropdown.find(".dropdown-item").not(".d-none")}QUnit.test("bsSelect search",function(assert){var done=assert.async();var $select=$('<select id="mySelect" data-bs-toggle="select"><option value="1">Apple</option><option value="2">Banana</option><option value="3">Avocado</option><option value="4">Apricot</option></select>');$("body").append($select);$(document).ready(function(){$select.bsSelect();var $dropdown=$select.closest(".js-bs-select-dropdown");var $searchInput=$dropdown.find('.dropdown-menu input[type="search"]');$searchInput.val("Ap").trigger("input");setTimeout(function(){var $visibleItems=getVisibleDropdownItems($dropdown);assert.equal($visibleItems.length,2,"Two items are visible (Apple, Apricot)");$searchInput.val("Banana").trigger("input");setTimeout(function(){$visibleItems=getVisibleDropdownItems($dropdown);assert.equal($visibleItems.length,1,"One item is visible (Banana)");$searchInput.val("xyz").trigger("input");setTimeout(function(){$visibleItems=getVisibleDropdownItems($dropdown);assert.equal($visibleItems.length,0,"No item is visible");$select.bsSelect("destroy");$select.remove();done()},1e3)},1e3)},1e3)})});QUnit.test("bsSelect reveals externally hidden select after initialization",function(assert){var $style=$("<style>.js-test-hidden-select.bs-select { display: none; }</style>").appendTo("head");var $select=$('<select id="hiddenInitSelect" class="js-test-hidden-select bs-select"><option value="1">Apple</option><option value="2">Banana</option></select>');$("body").append($select);assert.equal($select.css("display"),"none","Select is externally hidden before initialization");$select.bsSelect();var $dropdown=$select.closest(".js-bs-select-dropdown");assert.notOk($dropdown.hasClass("bs-select"),"Wrapper does not get the bs-select class from the plugin");assert.notEqual($dropdown.css("display"),"none","Dropdown wrapper is visible after initialization");$select.bsSelect("destroy");$select.remove();$style.remove()});QUnit.test("bsSelect predefined search prefix (searchQuery option)",function(assert){var done=assert.async();var $select=$('<select id="predefinedSearchSelect"><option value="1">Apple</option><option value="2">Banana</option><option value="3">Avocado</option><option value="4">Apricot</option></select>');$("body").append($select);$(document).ready(function(){$select.bsSelect({searchQuery:"Ap"});var $dropdown=$select.closest(".js-bs-select-dropdown");var $visibleItems=getVisibleDropdownItems($dropdown);assert.equal($visibleItems.length,2,"Two items are visible on init (Apple, Apricot)");var $prefixText=$dropdown.find(".input-group-text");assert.equal($prefixText.text(),"Ap",'Search field prefix contains "Ap"');var $searchInput=$dropdown.find('input[type="search"]');assert.equal($searchInput.val(),"","The actual search field is empty");$searchInput.val("r").trigger("input");$visibleItems=getVisibleDropdownItems($dropdown);assert.equal($visibleItems.length,1,'Only Apricot is visible after entering "r"');assert.equal($visibleItems.text().trim(),"Apricot","Found item is Apricot");$select.bsSelect("destroy");$select.remove();done()})});QUnit.test("bsSelect programmatic search with prefix",function(assert){var done=assert.async();var $select=$('<select id="programmaticSearchPrefixSelect" data-search-query="A"><option value="1">Apple</option><option value="2">Banana</option><option value="3">Avocado</option><option value="4">Apricot</option></select>');$("body").append($select);$(document).ready(function(){$select.bsSelect();var $dropdown=$select.closest(".js-bs-select-dropdown");$select.bsSelect("search","v");var $visibleItems=getVisibleDropdownItems($dropdown);assert.equal($visibleItems.length,1,'One item is visible after programmatic search "v" with prefix "A" (Avocado)');assert.equal($visibleItems.text().trim(),"Avocado","Found item is Avocado");$select.bsSelect("destroy");$select.remove();done()})});QUnit.test("bsSelect predefined prefix via data attribute",function(assert){var done=assert.async();var $select=$('<select id="dataAttrSearchSelect" data-search-query="Avocado"><option value="1">Apple</option><option value="2">Banana</option><option value="3">Avocado</option><option value="4">Apricot</option></select>');$("body").append($select);$(document).ready(function(){$select.bsSelect();var $dropdown=$select.closest(".js-bs-select-dropdown");var $visibleItems=getVisibleDropdownItems($dropdown);assert.equal($visibleItems.length,1,"One item is visible on init (Avocado)");var $prefixText=$dropdown.find(".input-group-text");assert.equal($prefixText.text(),"Avocado",'Prefix contains "Avocado"');$select.bsSelect("destroy");$select.remove();done()})});QUnit.test("bsSelect search allows spaces",function(assert){var done=assert.async();var $select=$('<select id="spaceSearchSelect"><option value="1">Apple Pie</option><option value="2">Banana</option></select>');$("body").append($select);$(document).ready(function(){$select.bsSelect();var $dropdown=$select.closest(".js-bs-select-dropdown");var $searchInput=$dropdown.find('input[type="search"]');var event=$.Event("keydown");event.code="Space";$searchInput.trigger(event);assert.notOk(event.isDefaultPrevented(),"Space key was not prevented");$searchInput.val("Apple ").trigger("input");assert.equal($searchInput.val(),"Apple ","Trailing space remains in the search field");$searchInput.val("   ").trigger("input");assert.equal($searchInput.val(),"   ","Multiple spaces remain in the search field");$select.bsSelect("destroy");$select.remove();done()})});QUnit.test("bsSelect predefined search prefix is kept after close",function(assert){var done=assert.async();var $select=$('<select id="persistSearchSelect" data-search-query="Apple"><option value="1">Apple</option><option value="2">Banana</option></select>');$("body").append($select);$(document).ready(function(){$select.bsSelect();var $dropdown=$select.closest(".js-bs-select-dropdown");var $searchInput=$dropdown.find('input[type="search"]');var $prefixText=$dropdown.find(".input-group-text");assert.equal($prefixText.text(),"Apple",'Search field prefix contains "Apple"');assert.equal($searchInput.val(),"","The actual search field is initially empty");$searchInput.val("Banana").trigger("input");assert.equal($searchInput.val(),"Banana",'Search value changed to "Banana"');$dropdown.trigger("hidden.bs.dropdown");setTimeout(function(){assert.equal($searchInput.val(),"","Search field is empty again after closing");$select.bsSelect("destroy");$select.remove();done()},100)})});